import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";
import {
  Container,
  Typography,
  Card,
  CardContent,
  Select,
  MenuItem,
  Box,
  Chip,
  Grid,
  CircularProgress,
  FormControl,
  InputLabel,
} from "@mui/material";
import { NotificationsActive, Event, School, Work } from "@mui/icons-material";

const TYPE_COLORS = {
  Placement: { color: "success", icon: <Work fontSize="small" /> },
  Event: { color: "primary", icon: <Event fontSize="small" /> },
  Result: { color: "secondary", icon: <School fontSize="small" /> },
  Default: { color: "default", icon: <NotificationsActive fontSize="small" /> },
};

const NotificationApp = () => {
  const [data, setData] = useState([]);
  const [category, setCategory] = useState("All");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadNotifications = async () => {
      try {
        const response = await axios.get("http://localhost:5000/api/notifications")
        setData(response.data.data || []);
      } catch (error) {
        console.error("Failed to sync notifications:", error);
      } finally {
        setLoading(false);
      }
    };
    loadNotifications();
  }, []);

  // Memoizing the filter prevents unnecessary re-calculations on every render
  const filteredList = useMemo(() => {
    return category === "All" 
      ? data 
      : data.filter((item) => item.Type === category);
  }, [category, data]);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" height="80vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={4}>
        <Typography variant="h4" fontWeight="700" color="text.primary">
          Updates & Alerts
        </Typography>

        <FormControl size="small" sx={{ minWidth: 150 }}>
          <InputLabel>Filter Category</InputLabel>
          <Select
            value={category}
            label="Filter Category"
            onChange={(e) => setCategory(e.target.value)}
          >
            <MenuItem value="All">All Updates</MenuItem>
            <MenuItem value="Placement">Placements</MenuItem>
            <MenuItem value="Event">Events</MenuItem>
            <MenuItem value="Result">Results</MenuItem>
          </Select>
        </FormControl>
      </Box>

      <Grid container spacing={3}>
        {filteredList.map((note) => {
          const style = TYPE_COLORS[note.Type] || TYPE_COLORS.Default;
          
          return (
            <Grid item xs={12} key={note.ID}>
              <Card 
                elevation={0} 
                sx={{ 
                  borderRadius: 3, 
                  border: '1px solid',
                  borderColor: 'divider',
                  transition: '0.3s',
                  '&:hover': { boxShadow: '0 4px 20px rgba(0,0,0,0.08)' }
                }}
              >
                <CardContent sx={{ display: 'flex', gap: 2, alignItems: 'flex-start' }}>
                  <Box 
                    sx={{ 
                      p: 1.5, 
                      borderRadius: 2, 
                      bgcolor: `${style.color}.light`, 
                      color: `${style.color}.main`,
                      display: 'flex'
                    }}
                  >
                    {style.icon}
                  </Box>
                  
                  <Box flexGrow={1}>
                    <Box display="flex" justifyContent="space-between" alignItems="center" mb={1}>
                      <Chip 
                        label={note.Type} 
                        size="small" 
                        color={style.color} 
                        variant="outlined" 
                      />
                      <Typography variant="caption" color="text.secondary">
                        {new Date(note.Timestamp).toLocaleString()}
                      </Typography>
                    </Box>
                    <Typography variant="body1" fontWeight="500">
                      {note.Message}
                    </Typography>
                  </Box>
                </CardContent>
              </Card>
            </Grid>
          );
        })}
      </Grid>
    </Container>
  );
};

export default NotificationApp;
